## Terrain summary





::: {.cell}

```{.r .cell-code .hidden}
attribute <- c("plan_curvature", "profile_curvature", "saga_wetness_index", "catchment_area", "relative_slope_position", "channel_network_distance", "elevation")

ag_data <- read_csv(here::here("./notebooks/ag_data_49.csv")) |>
  mutate(site = "Agriculture")
```

::: {.cell-output .cell-output-stderr .hidden}

```
Rows: 49 Columns: 22
── Column specification ────────────────────────────────────────────────────────
Delimiter: ","
dbl (22): plan_curvature, profile_curvature, saga_wetness_index, catchment_a...

ℹ Use `spec()` to retrieve the full column specification for this data.
ℹ Specify the column types or set `show_col_types = FALSE` to quiet this message.
```


:::

```{.r .cell-code .hidden}
for_data <- read_csv(here::here("./notebooks/forest_data_49.csv")) |>
  mutate(site = "Forest")
```

::: {.cell-output .cell-output-stderr .hidden}

```
Rows: 49 Columns: 16
── Column specification ────────────────────────────────────────────────────────
Delimiter: ","
dbl (16): plan_curvature, profile_curvature, saga_wetness_index, catchment_a...

ℹ Use `spec()` to retrieve the full column specification for this data.
ℹ Specify the column types or set `show_col_types = FALSE` to quiet this message.
```


:::

```{.r .cell-code .hidden}
all_terrain <- ag_data |>
  bind_rows(for_data) |>
  select(any_of(attribute), site) |>
  pivot_longer(plan_curvature:elevation) |>
  group_by(name, site) |>
  summarise(mean = mean(value, na.rm = T),
            sd = sd(value, na.rm = T),
            max = max(value, na.rm = T),
            min = min(value, na.rm = T),
            se = sd(value)/ sqrt(length(value)),
            skewness = moments::skewness(value),
            cv = sd(value, na.rm = TRUE) / mean(value, na.rm = TRUE) * 100, .groups = "drop") |>
  mutate(name = as.character(fct_recode(name,  "Elevation" = "elevation", "Catchment Area" = "catchment_area", "Plan Curvature" = "plan_curvature", "Profile Curvature" = "profile_curvature", "Rel. Slope Position" = "relative_slope_position", "SAGA Wetness Index" = "saga_wetness_index", "Vert. Dist. Channel" = "channel_network_distance")))
```
:::

::: {#tbl-univariate-summary2 .cell tbl-cap='Summary univariate statistics of terrain attributes for each site (n = 49).'}

```{.r .cell-code .hidden}
#| label: tbl-univariate-summary2
#| tbl-cap: Summary univariate statistics of terrain attributes for each site (n = 49).

all_terrain |>
  group_by(site) |>
  select( -se) |>
  gt() |>
  #fmt_markdown(columns = Element)|>
  fmt_number(decimals = 2) |>
  #cols_align(align = "left") |>
  tab_style(style =  cell_text(weight = "bold", align = "center"), locations =  cells_row_groups()) |>
  tab_options(column_labels.font.weight = "bold")
```

